import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6903_巨漢/20260502/G01_公司歷史與創辦人研究_投資研究員.md","filePath":"審計報告庫/經營審計/6903_巨漢/20260502/G01_公司歷史與創辦人研究_投資研究員.md"}'),l={name:"審計報告庫/經營審計/6903_巨漢/20260502/G01_公司歷史與創辦人研究_投資研究員.md"};function i(n,a,_,s,h,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司的歷史背景與創辦人為何？創辦人的經營理念是否影響公司的長期發展方向？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢由王滄鍊創立（1989 年），從水電空調工程起家，35 年深耕半導體廠務工程。2024 年以 151 元上櫃。經營風格穩健，零負債高現金。利空：創辦人年事已高（70+），接班透明度不足，總經理羅瑞鴻的實際決策權限待觀察。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（優）。創辦人持股穩定、經營團隊經驗豐富、公司歷史清白無重大爭議。利空：創辦人年事已高（70+），接班計畫透明度不足。目前總經理為羅瑞鴻（專業經理人），接班布局中，但關鍵人風險中等。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>創辦人背景</strong>：王滄鍊，1989 年以水電空調工程起家創立巨漢。早年承接政府水電工程，2000 年後轉型切入半導體廠房統包工程。2024 年成功上櫃。創辦人個性低調、重視品質，不喜炒作股票或追逐短線熱門議題。</p></li><li><p><strong>公司沿革</strong>：1989 年成立 → 1997 年取得 ISO 9002 認證 → 2000 年切入半導體廠務工程 → 2024 年上櫃。2025 年受惠於半導體擴產潮，營收暴增 72.8%。2026 年策略定調為「AI 基礎建設 + 公共工程」雙引擎。</p></li><li><p><strong>經營理念</strong>：創辦人奉行「穩健經營、品質優先」，不作價、不作帳、不參與政治關說。公司帳上現金 17-22 億無借款，反映創辦人風險趨避的性格，但也導致資金運用效率偏低。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>接班風險</strong>：創辦人王滄鍊年事已高，目前雖已交棒給羅瑞鴻擔任總經理，但董事長仍由創辦人兼任。若創辦人健康出現問題，可能影響公司重大決策效率。需關注接班計畫的透明度和深度。</li><li><strong>經營風格過於保守的利空</strong>：創辦人的穩健性格使公司零負債高現金，但也導致錯失擴張機會。若未來半導體擴產需求趨緩，公司的保守策略可能無法及時調整，導致成長動能不足。</li><li><strong>關鍵人風險</strong>：創辦人雖已交棒，但公司重大決策仍以創辦人意見為主。總經理羅瑞鴻的實際決策權限不明，若創辦人完全退休後管理層出現斷層，可能影響客戶關係維持。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：巨漢 6903 創辦人、公司沿革</li><li>FinMind：TaiwanStockInfo</li></ul>',12)])])}const u=e(l,[["render",i]]);export{p as __pageData,u as default};
